    public void saveBitmapToFile(Bitmap bmp, File file) { try { FileOutputStream fos = new FileOutputStream(file); bmp.compress(Bitmap.CompressFormat.PNG, 100, fos); fos.close(); } catch(Exception e){ e.printStackTrace(); } }
    public void saveDraft(String projectName) { if (loadingOverlay != null) loadingOverlay.setVisibility(View.VISIBLE); new Thread(() -> { try { File draftDir = new File(getExternalFilesDir(null), "OwnDrafts/" + projectName); if (!draftDir.exists()) draftDir.mkdirs(); if (editorView.baseImage != null) saveBitmapToFile(editorView.baseImage, new File(draftDir, "base.png")); if (editorView.drawingManager.getDrawLayerBitmap() != null) saveBitmapToFile(editorView.drawingManager.getDrawLayerBitmap(), new File(draftDir, "draw.png")); if (editorView.drawingManager.getEraseLayerBitmap() != null) saveBitmapToFile(editorView.drawingManager.getEraseLayerBitmap(), new File(draftDir, "erase.png")); JSONArray layersArr = new JSONArray(); for (int i=0; i<editorView.graphicLayers.size(); i++) { LayerSettingsUI.GraphicLayer gl = editorView.graphicLayers.get(i); JSONObject obj = new JSONObject(); obj.put("type", gl.type); obj.put("x", gl.x); obj.put("y", gl.y); obj.put("scaleX", gl.scaleX); obj.put("scaleY", gl.scaleY); obj.put("rotation", gl.rotation); obj.put("alpha", gl.alpha); obj.put("flipX", gl.flipX); obj.put("flipY", gl.flipY); obj.put("color", gl.color); obj.put("strokeWidth", (double) gl.strokeWidth); obj.put("strokeColor", gl.strokeColor); obj.put("shadowRadius", (double) gl.shadowRadius); obj.put("shadowColor", gl.shadowColor); obj.put("innerShadowRadius", (double) gl.innerShadowRadius); obj.put("innerShadowColor", gl.innerShadowColor); obj.put("shadowOffsetX", (double) gl.shadowOffsetX); obj.put("shadowOffsetY", (double) gl.shadowOffsetY); obj.put("innerShadowOffsetX", (double) gl.innerShadowOffsetX); obj.put("innerShadowOffsetY", (double) gl.innerShadowOffsetY); if (gl.type == 0) { obj.put("text", gl.text); obj.put("align", gl.align.name()); obj.put("letterSpacing", (double) gl.letterSpacing); obj.put("lineSpacing", (double) gl.lineSpacing); } else if (gl.type == 1 && gl.bitmap != null) { String fName = "layer_" + i + ".png"; saveBitmapToFile(gl.bitmap, new File(draftDir, fName)); obj.put("imageFile", fName); } layersArr.put(obj); } FileOutputStream fos = new FileOutputStream(new File(draftDir, "layers.json")); fos.write(layersArr.toString().getBytes("UTF-8")); fos.close(); runOnUiThread(() -> { if (loadingOverlay != null) loadingOverlay.setVisibility(View.GONE); Toast.makeText(this, "Draft Saved: " + projectName, Toast.LENGTH_SHORT).show(); }); } catch(Exception e) { runOnUiThread(() -> { if (loadingOverlay != null) loadingOverlay.setVisibility(View.GONE); Toast.makeText(this, "Failed to save draft", Toast.LENGTH_SHORT).show(); }); } }).start(); }
    public void loadDraft(String draftPath) { if (loadingOverlay != null) loadingOverlay.setVisibility(View.VISIBLE); new Thread(() -> { try { File draftDir = new File(draftPath); if (!draftDir.exists()) return; runOnUiThread(() -> { editorView.clearModifications(); if (tapToStartView != null) tapToStartView.setVisibility(View.GONE); }); File baseF = new File(draftDir, "base.png"); if (baseF.exists()) { Bitmap baseBmp = BitmapFactory.decodeFile(baseF.getAbsolutePath()); if (baseBmp != null) { if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O && baseBmp.getConfig() == Bitmap.Config.HARDWARE) { Bitmap sw = baseBmp.copy(Bitmap.Config.ARGB_8888, true); baseBmp.recycle(); baseBmp = sw; } final Bitmap fBase = baseBmp; runOnUiThread(() -> editorView.setImage(fBase)); } } Thread.sleep(200); File drawF = new File(draftDir, "draw.png"); if (drawF.exists() && editorView.drawingManager.getDrawLayerCanvas() != null) { Bitmap db = BitmapFactory.decodeFile(drawF.getAbsolutePath()); if (db != null) { editorView.drawingManager.getDrawLayerCanvas().drawBitmap(db, 0, 0, null); db.recycle(); } } File eraseF = new File(draftDir, "erase.png"); if (eraseF.exists() && editorView.drawingManager.getEraseLayerCanvas() != null) { Bitmap eb = BitmapFactory.decodeFile(eraseF.getAbsolutePath()); if (eb != null) { editorView.drawingManager.getEraseLayerCanvas().drawBitmap(eb, 0, 0, null); eb.recycle(); } } File jsonF = new File(draftDir, "layers.json"); if (jsonF.exists()) { InputStream is = new FileInputStream(jsonF); int size = is.available(); byte[] buffer = new byte[size]; is.read(buffer); is.close(); String json = new String(buffer, "UTF-8"); JSONArray arr = new JSONArray(json); List<LayerSettingsUI.GraphicLayer> loadedLayers = new ArrayList<>(); for (int i=0; i<arr.length(); i++) { JSONObject obj = arr.getJSONObject(i); int type = obj.getInt("type"); int color = obj.optInt("color", Color.WHITE); float strokeWidth = (float) obj.optDouble("strokeWidth", 0); int strokeColor = obj.optInt("strokeColor", Color.BLACK); float shadowRadius = (float) obj.optDouble("shadowRadius", 0); int shadowColor = obj.optInt("shadowColor", Color.BLACK); float innerShadowRadius = (float) obj.optDouble("innerShadowRadius", 0); int innerShadowColor = obj.optInt("innerShadowColor", Color.BLACK); float shadowOffsetX = (float) obj.optDouble("shadowOffsetX", 0); float shadowOffsetY = (float) obj.optDouble("shadowOffsetY", 0); float innerShadowOffsetX = (float) obj.optDouble("innerShadowOffsetX", 0); float innerShadowOffsetY = (float) obj.optDouble("innerShadowOffsetY", 0); LayerSettingsUI.GraphicLayer gl; if (type == 0) { android.text.Layout.Alignment align = android.text.Layout.Alignment.ALIGN_CENTER; try { align = android.text.Layout.Alignment.valueOf(obj.getString("align")); } catch(Exception e){} gl = new LayerSettingsUI.GraphicLayer(obj.getString("text"), null, color, align, (float)obj.optDouble("letterSpacing", 0), (float)obj.optDouble("lineSpacing", 0), strokeWidth, strokeColor, shadowRadius, shadowColor, innerShadowRadius, innerShadowColor, 0, 0); } else { String fName = obj.getString("imageFile"); Bitmap bmp = BitmapFactory.decodeFile(new File(draftDir, fName).getAbsolutePath()); if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O && bmp != null && bmp.getConfig() == Bitmap.Config.HARDWARE) { Bitmap sw = bmp.copy(Bitmap.Config.ARGB_8888, true); bmp.recycle(); bmp = sw; } gl = new LayerSettingsUI.GraphicLayer(bmp, 0, 0); gl.color = color; gl.strokeWidth = strokeWidth; gl.strokeColor = strokeColor; gl.shadowRadius = shadowRadius; gl.shadowColor = shadowColor; gl.innerShadowRadius = innerShadowRadius; gl.innerShadowColor = innerShadowColor; } gl.shadowOffsetX = shadowOffsetX; gl.shadowOffsetY = shadowOffsetY; gl.innerShadowOffsetX = innerShadowOffsetX; gl.innerShadowOffsetY = innerShadowOffsetY; gl.x = (float)obj.getDouble("x"); gl.y = (float)obj.getDouble("y"); gl.scaleX = (float)obj.getDouble("scaleX"); gl.scaleY = (float)obj.getDouble("scaleY"); gl.rotation = (float)obj.getDouble("rotation"); gl.alpha = obj.getInt("alpha"); gl.flipX = obj.getBoolean("flipX"); gl.flipY = obj.getBoolean("flipY"); loadedLayers.add(gl); } runOnUiThread(() -> { editorView.getLayers().addAll(loadedLayers); for(LayerSettingsUI.GraphicLayer l : loadedLayers) l.isDirty = true; editorView.invalidate(); refreshLayersPanel(); }); } runOnUiThread(() -> { if (loadingOverlay != null) loadingOverlay.setVisibility(View.GONE); Toast.makeText(this, "Draft Loaded Successfully!", Toast.LENGTH_SHORT).show(); }); } catch(Exception e) { runOnUiThread(() -> { if (loadingOverlay != null) loadingOverlay.setVisibility(View.GONE); Toast.makeText(this, "Failed to load draft", Toast.LENGTH_SHORT).show(); }); } }).start(); }
    public void toggleRightPanel() { if (rightToolsPanel != null) { if (rightToolsPanel.getVisibility() == View.VISIBLE) hideRightPanel(); else { showRightPanel(); hideLeftPanel(); } } }
    public void toggleLeftPanel() { if (leftLayersPanel != null) { if (leftLayersPanel.getVisibility() == View.VISIBLE) hideLeftPanel(); else { showLeftPanel(); hideRightPanel(); } } }
    public void hideRightPanel() { if (rightToolsPanel != null && rightToolsPanel.getVisibility() == View.VISIBLE) { rightToolsPanel.animate().translationX(rightToolsPanel.getWidth()).alpha(0f).setDuration(250).setInterpolator(new DecelerateInterpolator(2f)).withEndAction(() -> rightToolsPanel.setVisibility(View.GONE)).start(); if (panelOverlay != null && leftLayersPanel != null && leftLayersPanel.getVisibility() != View.VISIBLE) panelOverlay.animate().alpha(0f).setDuration(250).withEndAction(() -> panelOverlay.setVisibility(View.GONE)).start(); } }
    public void showRightPanel() { if (rightToolsPanel != null && rightToolsPanel.getVisibility() != View.VISIBLE) { rightToolsPanel.setVisibility(View.VISIBLE); rightToolsPanel.setTranslationX(rightToolsPanel.getWidth() > 0 ? rightToolsPanel.getWidth() : 300f); rightToolsPanel.setAlpha(0f); rightToolsPanel.animate().translationX(0).alpha(1f).setDuration(300).setInterpolator(new DecelerateInterpolator(2f)).start(); if (panelOverlay != null) { panelOverlay.setVisibility(View.VISIBLE); panelOverlay.setAlpha(0f); panelOverlay.animate().alpha(1f).setDuration(300).start(); } } }
    public void hideLeftPanel() { if (leftLayersPanel != null && leftLayersPanel.getVisibility() == View.VISIBLE) { leftLayersPanel.animate().translationX(-leftLayersPanel.getWidth()).alpha(0f).setDuration(250).setInterpolator(new DecelerateInterpolator(2f)).withEndAction(() -> leftLayersPanel.setVisibility(View.GONE)).start(); if (panelOverlay != null && rightToolsPanel != null && rightToolsPanel.getVisibility() != View.VISIBLE) panelOverlay.animate().alpha(0f).setDuration(250).withEndAction(() -> panelOverlay.setVisibility(View.GONE)).start(); } }
    public void showLeftPanel() { if (leftLayersPanel != null && leftLayersPanel.getVisibility() != View.VISIBLE) { leftLayersPanel.setVisibility(View.VISIBLE); leftLayersPanel.setTranslationX(leftLayersPanel.getWidth() > 0 ? -leftLayersPanel.getWidth() : -300f); leftLayersPanel.setAlpha(0f); leftLayersPanel.animate().translationX(0).alpha(1f).setDuration(300).setInterpolator(new DecelerateInterpolator(2f)).start(); if (panelOverlay != null) { panelOverlay.setVisibility(View.VISIBLE); panelOverlay.setAlpha(0f); panelOverlay.animate().alpha(1f).setDuration(300).start(); } } }
    public void showCropToolbar() { if (cropToolsBar != null && cropToolsBar.getVisibility() != View.VISIBLE) { cropToolsBar.setVisibility(View.VISIBLE); cropToolsBar.setTranslationY(200f); cropToolsBar.setAlpha(0f); cropToolsBar.animate().translationY(0).alpha(1f).setDuration(300).setInterpolator(new DecelerateInterpolator(2f)).start(); } }
