    public void exportImage(int formatIndex) { if (loadingOverlay != null) loadingOverlay.setVisibility(View.VISIBLE); Toast.makeText(this, "Processing and Saving...", Toast.LENGTH_SHORT).show(); new android.os.Handler(android.os.Looper.getMainLooper()).postDelayed(() -> { Bitmap finalImage = editorView.getRenderedBitmap(true); new Thread(() -> { try { String extension, mimeType; Bitmap.CompressFormat compressFormat; int quality = 100; Bitmap exportBmp = finalImage; boolean scaleDown = false; if (formatIndex == 0) { extension = ".png"; mimeType = "image/png"; compressFormat = Bitmap.CompressFormat.PNG; } else if (formatIndex == 1) { extension = ".png"; mimeType = "image/png"; compressFormat = Bitmap.CompressFormat.PNG; scaleDown = true; } else if (formatIndex == 2) { extension = ".jpg"; mimeType = "image/jpeg"; compressFormat = Bitmap.CompressFormat.JPEG; } else if (formatIndex == 3) { extension = ".jpg"; mimeType = "image/jpeg"; compressFormat = Bitmap.CompressFormat.JPEG; quality = 60; scaleDown = true; } else if (formatIndex == 4) { extension = ".webp"; mimeType = "image/webp"; compressFormat = (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) ? Bitmap.CompressFormat.WEBP_LOSSLESS : Bitmap.CompressFormat.WEBP; quality = 100; } else { extension = ".webp"; mimeType = "image/webp"; compressFormat = (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) ? Bitmap.CompressFormat.WEBP_LOSSY : Bitmap.CompressFormat.WEBP; quality = 60; scaleDown = true; } if (scaleDown) { exportBmp = Bitmap.createScaledBitmap(finalImage, Math.max(1, finalImage.getWidth()/2), Math.max(1, finalImage.getHeight()/2), true); } String fileName = "Edited_" + System.currentTimeMillis() + extension; ContentValues values = new ContentValues(); values.put(MediaStore.Images.Media.DISPLAY_NAME, fileName); values.put(MediaStore.Images.Media.MIME_TYPE, mimeType); if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) { values.put(MediaStore.Images.Media.RELATIVE_PATH, Environment.DIRECTORY_PICTURES + "/OWN's Image studio"); values.put(MediaStore.Images.Media.IS_PENDING, 1); } Uri uri = getContentResolver().insert(MediaStore.Images.Media.EXTERNAL_CONTENT_URI, values); if (uri != null) { OutputStream os = getContentResolver().openOutputStream(uri); if (os != null) { exportBmp.compress(compressFormat, quality, os); os.close(); } if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) { values.clear(); values.put(MediaStore.Images.Media.IS_PENDING, 0); getContentResolver().update(uri, values, null, null); } runOnUiThread(() -> { if (loadingOverlay != null) loadingOverlay.setVisibility(View.GONE); Toast.makeText(this, "Saved to Pictures/OWN's Image studio", Toast.LENGTH_LONG).show(); }); } else { runOnUiThread(() -> { if (loadingOverlay != null) loadingOverlay.setVisibility(View.GONE); Toast.makeText(this, "Export Failed", Toast.LENGTH_SHORT).show(); }); } } catch (OutOfMemoryError e) { runOnUiThread(() -> { System.gc(); if (loadingOverlay != null) loadingOverlay.setVisibility(View.GONE); Toast.makeText(this, "Image too large to save! Try compressed format.", Toast.LENGTH_LONG).show(); }); } catch (Exception e) { runOnUiThread(() -> { if (loadingOverlay != null) loadingOverlay.setVisibility(View.GONE); Toast.makeText(this, "Export Failed", Toast.LENGTH_SHORT).show(); }); } }).start(); }, 50); }
